enum DeviceCapability { screenShare, remoteControl, fileTransfer, voiceCall, location, parentalControls } extension DeviceCapabilityExt on DeviceCapability { String get label { switch(this) { case DeviceCapability.screenShare: return 'Screen Share'; case DeviceCapability.remoteControl: return 'Remote Control'; case DeviceCapability.fileTransfer: return 'File Transfer'; case DeviceCapability.voiceCall: return 'Voice Call'; case DeviceCapability.location: return 'Location'; case DeviceCapability.parentalControls: return 'Parental'; } } bool get requiresOnline => this != DeviceCapability.fileTransfer; }